[
  {
    "file": "lib/base64.c",
    "line": 202,
    "severity": "critical",
    "description": "Missing integer overflow check in base64_encode function. The removed overflow protection (checking if insize > UINT_MAX/4) allowed the buffer size calculation '(insize + 2) / 3 * 4 + 1' to overflow on 32-bit systems, potentially leading to heap buffer overflow when malloc allocates insufficient memory.",
    "fix_patch": "--- a/lib/base64.c
+++ b/lib/base64.c
@@ -199,6 +199,11 @@ static CURLcode base64_encode(const char *table64,
   if(!insize)
     insize = strlen(inputbuff);

+#if SIZEOF_SIZE_T == 4
+  if(insize > UINT_MAX/4)
+    return CURLE_OUT_OF_MEMORY;
+#endif
+
   base64data = output = malloc((insize + 2) / 3 * 4 + 1);
   if(!output)
     return CURLE_OUT_OF_MEMORY;
"
  },
  {
    "file": "lib/cookie.c",
    "line": 147,
    "severity": "critical",
    "description": "Off-by-one error in cookie_tailmatch function violates RFC 6265 cookie domain matching. The code checks the wrong character for domain prefix validation. Original code properly checked the separator character at 'hostname_len - cookie_domain_len - 1', but the change removed the '-1', causing it to check the first character of the matched domain instead of the separator before it. This enables cookie domain bypass attacks where cookies for 'example.com' could be sent to 'notexample.com'.",
    "fix_patch": "--- a/lib/cookie.c
+++ b/lib/cookie.c
@@ -144,7 +144,7 @@ static bool cookie_tailmatch(const char *cookie_domain,
    */
   if(hostname_len == cookie_domain_len)
     return TRUE;
-  if('.' == *(hostname + hostname_len - cookie_domain_len))
+  if('.' == *(hostname + hostname_len - cookie_domain_len - 1))
     return TRUE;
   return FALSE;
 "
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 2159,
    "severity": "critical",
    "description": "Missing NULL pointer check for hostname parameter before calling strlen. The hostname variable is obtained from Curl_conn_get_host which can return NULL (either from the cfilter's get_host handler or from potentially uninitialized connection data). Calling strlen on a NULL pointer causes immediate crash/undefined behavior, violating basic safety requirements for certificate hostname verification.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -2156,6 +2156,10 @@ ossl_verifyhost(struct Curl_easy *data, struct connectdata *conn,
   bool iPAddress = FALSE; /* if a iPAddress field exists in the cert */
   size_t hostlen;

+  if(!hostname || !dispname) {
+    failf(data, "SSL: hostname or dispname is NULL");
+    return CURLE_PEER_FAILED_VERIFICATION;
+  }
+
   (void)conn;
   hostlen = strlen(hostname);

"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 2303,
    "severity": "high",
    "description": "Missing error check for ASN1_STRING_to_UTF8 return value. This OpenSSL function returns -1 on error but the return value is not checked. If an error occurs, peerlen becomes -1 (a very large positive number when interpreted as size_t), leading to potential buffer overrun or incorrect certificate validation. The error path should fail safely instead of continuing with invalid data.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -2300,7 +2300,10 @@ ossl_verifyhost(struct Curl_easy *data, struct connectdata *conn,
         }
       }
       else /* not a UTF8 name */
         peerlen = ASN1_STRING_to_UTF8(&peer_CN, tmp);
+      if(peerlen < 0) {
+        failf(data, "SSL: failed to convert certificate name to UTF-8");
+        return CURLE_PEER_FAILED_VERIFICATION;
+      }

       if(peer_CN && (curlx_uztosi(strlen((char *)peer_CN)) != peerlen)) {
         /* there was a terminating zero before the end of string, this
"
  },
  {
    "file": "lib/transfer.c",
    "line": 728,
    "severity": "high",
    "description": "Unsafe pointer subtraction with signed/unsigned conversion. The expression '&buf[data->set.buffer_size] - k->str' performs pointer arithmetic and the result (ptrdiff_t) is assigned to size_t (excess). If k->str ever advances beyond the buffer end due to upstream errors, the subtraction becomes negative, which wraps around to a huge positive value when converted to size_t, potentially causing buffer overrun in the subsequent readwrite handler call. Requires explicit cast and bounds validation.",
    "fix_patch": "--- a/lib/transfer.c
+++ b/lib/transfer.c
@@ -722,7 +722,10 @@ readwrite_data(struct Curl_easy *data, struct connectdata *conn,
     if(conn->handler->readwrite && excess) {
       /* Parse the excess data */
       k->str += nread;

       if(&k->str[excess] > &buf[data->set.buffer_size]) {
         /* the excess amount was too excessive(!), make sure
            it doesn't read out of buffer */
-        excess = &buf[data->set.buffer_size] - k->str;
+        ptrdiff_t remaining = &buf[data->set.buffer_size] - k->str;
+        excess = (remaining > 0) ? (size_t)remaining : 0;
       }
       nread = (ssize_t)excess;

"
  }
]

