   148→    /* this means either 8 or 16 bits output */
   149→    unsigned char val;
   150→    unsigned int x = 0;
   151→    int j;
   152→    size_t padc = 0;
   153→    for(j = 0; j < 4; j++) {
   154→      if(*src == '=') {
   155→        x <<= 6;
   156→        src++;
   157→        if(++padc > padding)
   158→          /* this is a badly placed '=' symbol! */
   159→          goto bad;
   160→      }
   161→      else {
   162→        val = lookup[(unsigned char)*src++];
   163→        if(val == 0xff) /* bad symbol */
   164→          goto bad;
   165→        x = (x << 6) | val;
   166→      }
   167→    }
   168→    if(padding == 1)
   169→      pos[1] = (x >> 8) & 0xff;
   170→    pos[0] = (x >> 16) & 0xff;
   171→    pos += 3 - padding;
   172→  }
   173→
   174→  /* Zero terminate */
   175→  *pos = '\0';
   176→
   177→  /* Return the decoded data */
   178→  *outptr = newstr;
   179→  *outlen = rawlen;
   180→
   181→  return CURLE_OK;
   182→bad:
   183→  free(newstr);
   184→  return CURLE_BAD_CONTENT_ENCODING;
   185→}
