   245→/*
   246→ * Curl_base64_encode()
   247→ *
   248→ * Given a pointer to an input buffer and an input size, encode it and
   249→ * return a pointer in *outptr to a newly allocated memory area holding
   250→ * encoded data. Size of encoded data is returned in variable pointed by
   251→ * outlen.
   252→ *
   253→ * Input length of 0 indicates input buffer holds a NUL-terminated string.
   254→ *
   255→ * Returns CURLE_OK on success, otherwise specific error code. Function
   256→ * output shall not be considered valid unless CURLE_OK is returned.
   257→ *
   258→ * @unittest: 1302
   259→ */
   260→CURLcode Curl_base64_encode(const char *inputbuff, size_t insize,
   261→                            char **outptr, size_t *outlen)
   262→{
   263→  return base64_encode(base64encdec, inputbuff, insize, outptr, outlen);
   264→}
