   275→ *
   276→ * Returns CURLE_OK on success, otherwise specific error code. Function
   277→ * output shall not be considered valid unless CURLE_OK is returned.
   278→ *
   279→ * @unittest: 1302
   280→ */
   281→CURLcode Curl_base64url_encode(const char *inputbuff, size_t insize,
   282→                               char **outptr, size_t *outlen)
   283→{
   284→  return base64_encode(base64url, inputbuff, insize, outptr, outlen);
   285→}
